if (authType === WebhookAuthEnum.TOKEN) {
  requestConfig.headers = {
    Authorization: cmd.auth?.token,
  };
} else if (authType === WebhookAuthEnum.API_KEY) {
  const addTo = cmd.auth?.addTo as WebhookApiKeyFieldEnum;

  if (addTo === WebhookApiKeyFieldEnum.HEADER) {
    requestConfig.headers = {
      [cmd.auth?.key]: cmd.auth?.value,
    };
  } else if (addTo === WebhookApiKeyFieldEnum.PARAMS) {
    requestConfig.url = `?${cmd.auth?.key}=${cmd.auth?.value}`;
  }
} else if (authType === WebhookAuthEnum.OAUTH_2) {
  const addTo = cmd.auth?.addTo as WebhookApiKeyFieldEnum;
  if (addTo === WebhookApiKeyFieldEnum.HEADER) {
    requestConfig.headers = {
      Authorization: cmd.auth?.token,
    };
  } else if (addTo === WebhookApiKeyFieldEnum.PARAMS) {
    requestConfig.url = `?Authorization=${cmd.auth?.token}`;
  }
}

if (field.isSave) {
  detailFields += `'${camelCaseName}',`
  const apiProperty = `@ApiProperty({ description: '${field.description}', required: ${field.isRequired} })`
  const type = this.mapDbTypeToTsType(field.type)
  const capitalType = type.charAt(0).toUpperCase() + type.slice(1)
  let validator = `@Is${capitalType}({ message: '${field.description}，格式错误' })`
  if (type === 'any') {
    dtoNeedMap.needIsObject = true
    validator = undefined
  }
  if (type === 'number') {
    dtoNeedMap.needIsNumber = true
    validator = `@IsNumber({}, { message: '${field.description}，格式错误' })`
  }
  if (type === 'string') {
    dtoNeedMap.needIsString = true
  }
  if (type === 'boolean') {
    dtoNeedMap.needIsBoolean = true
  }
  saveDtoFields.push({
    apiProperty,
    validator,
    name: camelCaseName,
    required: field.isRequired,
    type
  })
}

